var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"꺄아악! 도둑… 아니 괴도야!","JPN":"きゃああっ！　泥棒……じゃなくて、怪盗だぁ！","ENG":"Kyaah! It's a burg– I mean thief!","TWN":"呀啊啊！有小偷…不，有怪盜呀！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"괜찮으세요? 괴도는 어디 있죠?!","JPN":"大丈夫ですか？　怪盗はどこです！？","ENG":"Are you okay? Which way did the thief go?!","TWN":"你沒事吧？怪盜在哪裡？！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"……메이드 씨?","JPN":"……メイドさん？","ENG":"...Ms. Maid?","TWN":"…女僕小姐？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"응? 아, 아냐! 아무것도 안 먹었어!","JPN":"え？　ち、違うの！　何も食べてないよ！","ENG":"Hmm? O-oh, no! I didn't eat anything!","TWN":"嗯？沒、沒有！我什麼都沒吃！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"이건 내 몫이라고. 아가씨가 나한테만 특별히 챙겨주신 거야!","JPN":"これはアタシの分。お嬢様がアタシにだけ特別に用意してくれたの！","ENG":"This is mine. Miss Lin always prepares my share for me!","TWN":"這是我的那一份，是小姐特意為我準備的！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"그럼 괴도는요?","JPN":"じゃあ、怪盗は？","ENG":"And what about the thief?","TWN":"那怪盜呢？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"응? 아아… 여기 예고장.","JPN":"え？　ああ……これ、予告状だよ。","ENG":"Hmm? Oh, right... Here's the calling card.","TWN":"嗯？喔喔…這是預告函。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"네?!","JPN":"はい！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"흐음… 이게 그 두 번째 예고장이라는 거지?","JPN":"ふむ……これがその2番目の予告状か。","ENG":"Hmm... So this is the second calling card, eh?","TWN":"嗯…所以這是第二個預告函？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"어떻게 예고장을 두고 갈 수 있었을까요?","JPN":"どうやって予告状を置いて行ったのでしょうか？","ENG":"But how was she able to leave it right under our noses?","TWN":"她是怎麼留下預告函的呢？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"당신이 최초 보고자니까 말해주세요. 어디서 이걸 발견하셨죠?","JPN":"第一発見者に聞きましょう。これをどこで見つけたのですか？","ENG":"Since you're the first witness, tell us. Where did you find it?","TWN":"女僕小姐，你是第一個目擊者，請告訴我，你是在哪裡找到這個的？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"응? 그냥 밖에서 주길래 받아온 것뿐인데?","JPN":"え？　普通に外で渡されたよ。","ENG":"Hmm? She just gave it to me outside, so I took it.","TWN":"嗯？外面有人給我，我就收下了啊？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"뭐, 뭐라고요?!","JPN":"な、何ですって！？","ENG":"W-what?!","TWN":"什、什麼？！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"글쎄, 그 여자가 대뜸 햄버거를 건네주지 뭐야! 무려 수제 버거였다구!","JPN":"それがね、あの女が急にハンバーガーをくれたの！　しかも手作りバーガー！","ENG":"Well, some girl just came up to me and gave me a burger! A gourmet one at that!","TWN":"嗯！那個女人突然就把漢堡遞給我！而且還是手工漢堡！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"아침이 오면 괴도가 왔다고 소리만 질러주면 된다고 했어.","JPN":"見返りは、朝になったら怪盗が現われたって叫ぶだけだって。","ENG":"She said that all I had to do was scream that a thief broke in when morning came.","TWN":"還說，到早上的時候，只要大喊一聲怪盜來了！就可以了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"그래서…. 그냥 받아준 것뿐이야!","JPN":"だから……アタシはこれをもらっただけだよ！","ENG":"So... I just said yes!","TWN":"所以…我才收下的！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"햄버거 하나 줬다고 괴도가 시키는 대로 한겁니까?","JPN":"ハンバーガー一つで、怪盗の指示に従ったんですか？","ENG":"You aided a thief because she gave you a burger?","TWN":"就因為一個漢堡，你就按照怪盜說的做了？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"만약 그대로 들어왔으면 큰일 날 뻔했잖습니까!","JPN":"もしそのまま入ってきたら、大変なことになるところでしたよ！","ENG":"Had she come in, it would've been a disaster!","TWN":"如果讓她就這麼進來了，那可是一件很嚴重的事情！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"흥이다! 햄버거 주는 사람 중에 나쁜 사람은 없거든요?!","JPN":"フーンだ！　ハンバーガーをくれる人の中に、悪い人はいないの！","ENG":"Hmph! There are no bad people who give away burgers, you know!","TWN":"哼！送漢堡的人怎麼可能是壞人？！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FOOLSDAY_LUNA_MAID_NULL","text":{"KOREA":"그리고 안 들어왔거든요~ 예고장만 전달해달라 해서 받아준 것뿐이거든요~","JPN":"それに、入って来なかったでしょ？　予告状を渡してくれって頼まれたから、手伝ってあげただけだよ。","ENG":"And she didn't come in! She just asked me to deliver the calling card and that's what I did!","TWN":"而且她也沒進來啊～只是要求我轉交預告函，所以才收下的～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FOOLSDAY_DRAKO_MAID_NULL","text":{"KOREA":"에휴… 이젠 때리기도 지친다.","JPN":"はあ……もう殴るのも疲れた。","ENG":"Ugh... I'm tired of hitting you now.","TWN":"真是的…我現在都懶得打你了。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"FOOLSDAY_DRAKO_MAID_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"FOOLSDAY_LUNA_MAID_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"XIEN_FREEDOM_SPRING_NULL","text":{"KOREA":"예고장엔 뭐라고 적혀있지? 한번 볼까?","JPN":"予告状には何と書いてある？　見てみるか。","ENG":"What does it say on the calling card? Let's open it and read it.","TWN":"預告函裡寫了什麼？一起來看看吧。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"XIEN_FREEDOM_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};